mapper.select:
SELECT t1.ID, t1.DISPOSAL_NUM, t1.DISPOSAL_TITLE, t1.DISPOSAL_TYPE, t1.DISPOSAL_AMOUNT, t1.CREATED_USER, t1.CREATED_TIME, T2.DICT_LABEL FROM E_MATERIAL_WASTE_DISPOSAL t1 LEFT JOIN M_DICT_DATA t2 ON t2.DICT_VALUE = t1.DISPOSAL_TYPE AND t2.DICT_TYPE = 'DISPOSAL_TYPE'
AND t1.DISPOSAL_TITLE LIKE #{disposalTitle}
AND t1.t1.DISPOSAL_NUM, LIKE #{disposalNum}
order by CREATED_TIME DESC

mapper.insert:
INSERT INTO E_MATERIAL_WASTE_DISPOSAL ( ID, DISPOSAL_NUM, DISPOSAL_TITLE, DISPOSAL_TYPE, DISPOSAL_AMOUNT, CREATED_USER, CREATED_TIME
) values ( #{id}, #{disposalNum}, #{disposalTitle}, #{disposalType}, #{disposalAmount}, #{loginUserId,jdbcType=NUMERIC}, #{now,jdbcType=TIMESTAMP}
)
